import type { Recipe } from '@/types/database';
export function RecipeCard({recipe}:{recipe:Recipe}){return <article className="card"><div className="mb-3 h-32 rounded-3xl bg-gradient-to-br from-brand-100 to-white"/><span className="badge">{recipe.category}</span><h3 className="mt-3 text-xl font-black">{recipe.name}</h3><p className="mt-2 text-sm text-slate-600">{recipe.calories} kcal • {recipe.protein_g}g proteína • {recipe.prep_time_minutes} min</p><details className="mt-3"><summary className="cursor-pointer font-semibold">Ver preparo</summary><p className="mt-2 text-sm text-slate-600">{recipe.ingredients.join(', ')}</p><p className="mt-2 text-sm">{recipe.preparation}</p><p className="mt-2 text-sm text-brand-700">{recipe.healthy_note}</p></details></article>}
